var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"크으윽……!","JPN":"くううっ……！","ENG":"Urgh...!","TWN":"咳呃呃……！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"더 이상은 못 참아! 대체 언제까지 내가 네 녀석들 뒷바라지를 해야 하는 거냐!","JPN":"もう我慢の限界だ！　いつまであんたらの世話をしなきゃならないんだ！","ENG":"I can't take it anymore! How long am I supposed to babysit you people?!","TWN":"我再也忍不住了！我到底要照顧你們這些傢伙到什麼時候！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"너희들이 들러붙은 뒤로 사무실에 하와이안 피자 냄새가 진동한다고!","JPN":"あんたらが居候し出してから、すっかり事務所にハワイアンピザの匂いが染みついちまった！","ENG":"Ever since you latched on, the office reeks of Hawaiian pizza!","TWN":"自從你們待在這裡之後，整個辦公室都是夏威夷披薩的味道！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그것 참 멋진 일이군. 이 참에 별명을 스마트가이에서 스위트가이로 바꾸는 건 어때?","JPN":"そりゃよかったな。これを機にコールサインをスマートガイからスイートガイに変えるのはどうだ？","ENG":"How charming. How about changing your nickname from Smart Guy to Sweet Guy?","TWN":"這是件很棒的事，趁這機會把綽號從聰明男孩改成甜美男孩怎麼樣？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"달콤한 파인애플만큼 멋진 이름이라고 생각하는데.","JPN":"甘いパイナップルのように素敵な名前だと思うが。","ENG":"I think it's as sweet as a pineapple.","TWN":"我覺得這稱號就像香甜的鳳梨一樣美好。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"괜찮은데? 요즘 젊은 애들은 딱딱한 남자보다 달콤한 듯 부드러운 남자를 선호한다고.","JPN":"いいんじゃないか。最近の若者にはお堅い男よりは甘くて柔らかい男がモテるんだぜ。","ENG":"Sounds good to me. Kids these days prefer guys who are sweet and soft over stiff types.","TWN":"不錯耶？聽說最近年輕人比起死板的男人，更喜歡甜美溫柔的男人。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"그래. 먹다 보니 이 피자도 나름 괜찮고 말이야.","JPN":"そうそう。食べ慣れるとこのピザも結構うまいしな。","ENG":"Yeah. And you know, this pizza isn't half bad once you keep eating it.","TWN":"沒錯，吃到後來也覺得這個披薩很不錯。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"군인 놈들은 평시에도 전투식량이나 먹어댈 줄 알았는데, 제법 센스가 괜찮잖아?","JPN":"軍人のやつらは戦場以外でも戦闘食糧ばっかり食ってるもんだと思ってたけど、なかなかいいセンスしてるな。","ENG":"I figured soldiers ate MREs even off duty, but you've actually got taste.","TWN":"我還以為軍人平常也都是吃野戰口糧，但還滿有品味的嘛？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"용병 치고는 뭘 좀 아네, 형씨. 어디 사는 스마트가이보다 백 번 나아.","JPN":"傭兵の割に分かってるじゃないか。どこぞのスマートガイよりずっとマシだ。","ENG":"For a merc, you know a thing or two, pal. You're a hundred times better than a certain Smart Guy I know.","TWN":"就傭兵而言，你還挺懂的，老兄。比住在某個地方的聰明男孩好一百倍。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"아니, 이젠 스위트가이인가?","JPN":"いや、スイートガイと呼ぶべきか？","ENG":"Or is it Sweet Guy now?","TWN":"等等，現在是甜美男孩嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"하하하!!","JPN":"ははは！！","ENG":"Hahaha!!","TWN":"哈哈哈！！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이렇게는 못살아! 여긴 내 사무실이란 말이다!!","JPN":"こんな生活やってられるか！　ここは俺の事務所だぞ！！","ENG":"I can't live like this! This is my office!","TWN":"我沒辦法這ˋ樣過下去！這裡可是我的辦公室！！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"진정하세요. 저래도 들러붙은 값만큼은 톡톡히 치르고 있잖아요?","JPN":"落ち着いてください。あれでも居候してる分は働いてもらってるじゃありませんか。","ENG":"Easy, boss. For how much she's been glued to us, she's at least paying her \\"cling fee,\\" yeah?","TWN":"冷靜點，至少他們待在這裡付的錢也不少吧？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"요즘 벌이도 시원찮은데, 하와이안 피자 정도면 점심으로는 나름 호화스럽죠.","JPN":"最近売上も落ちているのに、ハワイアンピザなら十分豪華な昼食です。","ENG":"Business has been trash lately. A Hawaiian pizza for lunch? That's downright luxury.","TWN":"最近錢也不好賺，夏威夷披薩當作午餐也算豪華了。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"……파인애플만 빼면, 어쨌든 피자니까.","JPN":"……パイナップルが乗っているというだけで、ピザはピザですから。","ENG":"...Pineapple crimes aside, pizza's still pizza.","TWN":"……撇除鳳梨不說，總之是披薩。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그래, 메이슨 씨. 좋은 게 좋은 거야.","JPN":"そうだぞ、メイソンさんよ。ポジティブ思考が一番ってことさ。","ENG":"Let good enough be good enough, Mr. Mason.","TWN":"是啊，梅森，就別再挑剔了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"이 달콤함에 거스를 생각 말고 시대의 흐름에 합류하라고.","JPN":"この甘さに逆らわず、時代の流れに身を委ねろ。","ENG":"Stop fighting the sweetness and join the times.","TWN":"別想抗拒這份甜蜜，要加入時代的潮流。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"시대의 흐름이고 자시고, 군인이 이렇게 놀고먹기만 해도 되는 건가?","JPN":"時代の流れはともかく、軍人がこうやって暇してていいのか？","ENG":"Trend or not, are soldiers really allowed to loaf around like this?","TWN":"管他什麼時代的潮流，軍人可以這樣游手好閒嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"알면서 뭘 그래? 델타 세븐은 클리포트 게임 당시 검은 평의회와 협력했다고.","JPN":"知ってるだろう？　デルタセブンはクリフォトゲーム当時、黒い評議会に協力した。","ENG":"You know the score. Delta Seven teamed up with the Dark Council during the Qliphoth Game.","TWN":"你明知道幹嘛還這樣？ 第七三角洲在逆卡巴拉遊戲當時和黑暗評議會合作了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그런 범죄조직이랑 손을 잡았으니, 높으신 분들의 비위가 어련하겠어?","JPN":"犯罪組織と手を組んだのに、上の方々の機嫌が良いわけないだろ？","ENG":"We shook hands with a crime syndicate. The bigwigs aren't exactly thrilled.","TWN":"既然已經和那種犯罪組織聯手，還能怎麼討好上位的人？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"세상을 구한 일은 뒷전으로 미루고 당장 무기한 근신처분이 내려와도 어쩔 수 없지.","JPN":"世界を救った功績を称えるより先に、無期限謹慎処分を下されても仕方ない。","ENG":"Even if saving the world gets brushed aside, an indefinite suspension was bound to land.","TWN":"就算把拯救世界的事拋諸腦後，立即下達無限期停職處分也沒辦法。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 말은, 징계를 받았으면 반성하는 기미를 보이란 말이야.","JPN":"俺が言いたいのは、懲戒を受けているなら反省しているふりでもしろってことだ。","ENG":"My point is, if you're disciplined, at least act like you're reflecting.","TWN":"我的意思是既然受到懲處，就要展現出反省之意。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 사무실을 본인 비밀기지처럼 들락거리지 말고!","JPN":"さも自分の秘密基地のように俺の事務所に出入りするんじゃなくてな！","ENG":"And stop treating my office like your secret base!","TWN":"不要把我辦公室當成自己的秘密基地一樣進進出出！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그건 어렵겠군. 부대에서는 카일이랑 실비아 눈치 보느라 이렇게 지낼 수가 없다고.","JPN":"それは無理だな。部隊だとカイルとシルビアの目が気になってくつろげないんだ。","ENG":"That's tough. Back on base I have to watch Kyle and Sylvia breathing down my neck.","TWN":"這應該很難，因為在部隊裡要看凱爾和希爾維亞的臉色，沒辦法這樣生活。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"근신을 휴가처럼 사용하지 마!","JPN":"謹慎は休暇じゃないんだぞ！","ENG":"Don't treat a suspension like a vacation!","TWN":"不要把停職當休假一樣使用！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"폰 진동음? 설마 의뢰 요청인가?","JPN":"携帯の振動？　まさか依頼が来たのか？","ENG":"Phone vibrating? Don't tell me it's a job request.","TWN":"手機震動？難道是委託請求？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"유감이지만 저쪽 대령님 폰이네요.","JPN":"残念ですが、あちらの大佐の携帯ですね。","ENG":"Hate to break it to you, but that's the Colonel's phone.","TWN":"雖然很遺憾，但那是上校的手機。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"발신자 표시 제한인데 끊을까요?","JPN":"発信者不明ですが、切りましょうか？","ENG":"Caller ID's blocked. Should I just kill the call?","TWN":"沒有來電顯示，要不要掛掉？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"그건 안 돼, 아가씨. 이래봬도 높으신 분들에게 제법 인기있는 편이거든.","JPN":"それはいけない、嬢ちゃん。こう見えて俺はお偉いさんたちにモテるんでね。","ENG":"Can't do that, miss. Like it or not, the bigwigs kind of like me.","TWN":"不行，小姐，別看我這樣，我很受上頭歡迎。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"뭐, 지금 상황에서 호출 받을 일은 없겠지만.","JPN":"ま、今の状況で呼び出されるなんて、ないと思うが。","ENG":"Though no one will be calling me in under these circumstances.","TWN":"嗯，雖然現在這情況下應該不會被呼叫。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"이런, 아무래도 귀찮은 일에 휘말린 것 같은데.","JPN":"はあ、どうやら厄介なことに巻き込まれてしまったようだな。","ENG":"Well, looks like we just got dragged into a pain in the neck.","TWN":"哎呀，總覺得是被捲入麻煩事了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"흥. 그럼 그렇지. 세금으로 일하는 공무원이면 가서 일이나 해.","JPN":"ふん、ざまあ見ろ。税金で食ってる公務員はとっとと仕事に戻れ。","ENG":"Hmph. Figures. If you're a taxpayer-paid civic servant, go do your job.","TWN":"嗯，我想也是。領稅金工作的公務員就去做你的工作吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"메이슨 씨. 사람 말은 끝까지 듣는 편이 좋아.","JPN":"メイソンさん、人の話は最後まで聞いたほうがいい。","ENG":"Mason, it helps to hear people out before you jump to conclusions.","TWN":"梅森，還是把別人的話聽完比較好。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_SKIN","text":{"KOREA":"귀찮은 일에 휘말린 건, <color=#ffd34c>우리</color>라고.","JPN":"厄介なことに巻き込まれちまったのは、<color=#ffd34c>俺たち</color>だ。","ENG":"The ones getting dragged in are <color=#ffd34c>us</color>.","TWN":"被捲入麻煩事的人是<color=#ffd34c>我們</color>。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_SKIN","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};